rd\r\n                        v-model=\"pin\"\r\n                    ></el-input>\r\n                </div>\r\n                <div\r\n                    v-if=\"transfer\"\r\n                    class=\"col-md-4 d-flex align-items-end justify-content-start\"\r\n                >\r\n                    <el-button type=\"primary\" @click=\"acceptTransfers\">\r\n                        Aceptar\r\n                    </el-button>\r\n                </div>\r\n            </div>\r\n            <template v-if=\"transfer\">\r\n                <div class=\"d-flex flex-column\" style=\"margin-top:10px;\">\r\n                    <h5>\r\n                        De:\r\n                        <strong>{{ transfer.warehouse.description }}</strong>\r\n                    </h5>\r\n                    <h5>\r\n                        A:\r\n                        <strong>{{\r\n                            transfer.warehouse_destination.description\r\n                        }}</strong>\r\n                    </h5>\r\n                </div>\r\n                <div class=\"row\" style=\"margin-top:10px;\">\r\n                    <table>\r\n                        <thead>\r\n                            <tr>\r\n                                <th>#</th>\r\n                                <th>Producto</th>\r\n                                <th>Cantidad</th>\r\n                            </tr>\r\n                        </thead>\r\n\r\n                        <tbody>\r\n                            <tr\r\n                                v-for=\"(data, idx) in transfer.detail\"\r\n                                :key=\"idx\"\r\n                            >\r\n                                <td>{{ idx + 1 }}</td>\r\n                                <td>{{ data.item.description }}</td>\r\n                                <td>{{ data.quantity }}</td>\r\n                            </tr>\r\n                        </tbody>\r\n                    </table>\r\n                </div>\r\n            </template>\r\n            <div class=\"p-3\"></div>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\"],\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            code: null,\r\n            pin: null,\r\n            transfer: null,\r\n            time: null\r\n        };\r\n    },\r\n    methods: {\r\n        async acceptTransfers() {\r\n            try {\r\n                this.loading = true;\r\n                const form = {\r\n                    code: this.code,\r\n                    pin: this.pin\r\n                };\r\n                const response = await this.$http.post(\r\n                    \"/transfers/accept_transfer\",\r\n                    form\r\n                );\r\n                const { success, message } = response.data;\r\n                if (success) {\r\n                    this.$toast.success(message);\r\n                } else {\r\n                    this.$toast.error(message);\r\n                }\r\n\r\n                this.close();\r\n            } catch (e) {\r\n                this.$toast.error(`Ocurrió un error ${e}`);\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async getTransfer() {\r\n            if (this.code.length == 5) {\r\n                if (this.time) {\r\n                    clearTimeout(this.time);\r\n                }\r\n\r\n                this.time = setTimeout(async () => {\r\n                    try {\r\n                        this.loading = true;\r\n                        const response = await this.$http(\r\n                            `/transfers/places?code=${this.code}`\r\n                        );\r\n                        const { message, success, transfer } = response.data;\r\n                        if (success) {\r\n                            this.transfer = transfer;\r\n                        } else {\r\